import{_ as t,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"S3 Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/s3.md","filePath":"ta/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ta/upload/s3.md"};function r(p,e,h,u,m,b){return i(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="s3-channel-சேர்க்கவும்" tabindex="-1">S3 Channel சேர்க்கவும் <a class="header-anchor" href="#s3-channel-சேர்க்கவும்" aria-label="Permalink to &quot;S3 Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="எப்போது-பயன்படுத்துவது" tabindex="-1">எப்போது பயன்படுத்துவது <a class="header-anchor" href="#எப்போது-பயன்படுத்துவது" aria-label="Permalink to &quot;எப்போது பயன்படுத்துவது&quot;">​</a></h2><p>S3 channel பயன்படுத்தலாம், நீங்கள்:</p><ul><li>Cloudflare R2, Backblaze B2, MinIO, AWS S3 அல்லது மற்ற S3-compatible object storage service ஒன்றை connect செய்ய விரும்பினால்.</li><li>standard S3 model-ஐ விரும்பினால்: <code>Endpoint</code>, Access Key, Secret Key.</li><li>native Cloudflare R2 binding channel பயன்படுத்த விரும்பவில்லை என்றால், அல்லது provider Cloudflare R2 அல்ல என்றால்.</li></ul><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>object storage service-இன் S3 API endpoint.</td></tr><tr><td>Bucket name</td><td>files சேமிக்கப்படும் bucket.</td></tr><tr><td>Region</td><td>storage region. Cloudflare R2-க்கு பொதுவாக <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>file access-க்கு optional custom domain.</td></tr></tbody></table><p>Cloudflare R2-ஐ S3 API மூலம் பயன்படுத்தும் உதாரணம்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="எங்கு-சேர்ப்பது" tabindex="-1">எங்கு சேர்ப்பது <a class="header-anchor" href="#எங்கு-சேர்ப்பது" aria-label="Permalink to &quot;எங்கு சேர்ப்பது&quot;">​</a></h2><ol><li>System Settings திறக்கவும்.</li><li>Upload Settings-க்கு செல்லவும்.</li><li>மேல் வலது மூலையில் Add Channel கிளிக் செய்யவும்.</li><li><code>S3</code> தேர்வு செய்யவும்.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>பயன்பாடு</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>இந்த S3 channel-க்கு எளிதாக அறியக்கூடிய பெயர், உதா. <code>s3test</code> அல்லது <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>இந்த channel upload selection-ல் பங்கேற்க வேண்டுமா என்பதை கட்டுப்படுத்தும்.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>முழு S3 service endpoint, <code>https://</code> உடன்.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional. set செய்தால் generated file links இந்த domain-ஐ முன்னுரிமை தரும்.</td><td>No</td></tr><tr><td>Bucket name</td><td>bucket name, உதா. <code>s3test</code> அல்லது <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. Cloudflare R2-க்கு பொதுவாக <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>compatibility switch. default off. சில MinIO, OpenList, self-hosted S3 services-க்கு தேவைப்படலாம்.</td><td>No</td></tr><tr><td>Quota limit</td><td>capacity அடிப்படையில் upload selection-ஐ கட்டுப்படுத்தும்.</td><td>No</td></tr><tr><td>Capacity limit</td><td>quota limit enabled ஆன பிறகு required, உதா. <code>10 GB</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Threshold</td><td>usage இந்த percentage அடைந்ததும் write நிறுத்தும், உதா. <code>90%</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Remark</td><td>உங்கள் maintenance notes.</td><td>No</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-keys-உருவாக்கவும்" tabindex="-1">Cloudflare R2 S3 API Keys உருவாக்கவும் <a class="header-anchor" href="#cloudflare-r2-s3-api-keys-உருவாக்கவும்" aria-label="Permalink to &quot;Cloudflare R2 S3 API Keys உருவாக்கவும்&quot;">​</a></h2><ol><li>Cloudflare Dashboard திறக்கவும்.</li><li><code>R2 Object Storage</code>-க்கு செல்லவும்.</li><li><code>Manage R2 API Tokens</code> அல்லது API token management entry கண்டறியவும்.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>target bucket அணுகக்கூடிய R2 API token உருவாக்கவும்.</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>generated <code>Access Key ID</code> மற்றும் <code>Secret Access Key</code> copy செய்யவும்.</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>R2 bucket page-க்கு திரும்பி bucket name confirm செய்யவும்.</li><li>account-இன் S3 API endpoint note செய்யவும். பொதுவாக:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings திறக்கவும்.</li><li>Add Channel கிளிக் செய்யவும்.</li><li><code>S3</code> தேர்வு செய்யவும்.</li><li>அறியக்கூடிய channel name உள்ளிடவும், உதா. <code>s3test</code>.</li><li><code>Endpoint</code>-ல் S3 API endpoint உள்ளிடவும்.</li><li>custom CDN இருந்தால் <code>Custom CDN domain</code> நிரப்பவும்; இல்லையெனில் காலியாக விடவும்.</li><li>bucket name உள்ளிடவும்.</li><li>region உள்ளிடவும். Cloudflare R2 உதாரணத்துக்கு <code>auto</code>.</li><li>Access Key ID மற்றும் Secret Access Key உள்ளிடவும்.</li><li>provider தெளிவாக கேட்கவில்லை என்றால் path-style access off வைத்திருக்கவும்.</li><li>capacity control வேண்டும் என்றால் quota limit enable செய்து capacity limit மற்றும் threshold நிரப்பவும்.</li><li>Save கிளிக் செய்யவும்.</li></ol><p><img src="'+d+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="verify-செய்வது" tabindex="-1">Verify செய்வது <a class="header-anchor" href="#verify-செய்வது" aria-label="Permalink to &quot;Verify செய்வது&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>சரிபார்ப்பு</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save செய்த பிறகு Upload Settings-ல் S3 channel card தெரியும்.</td></tr><tr><td>Channel is enabled</td><td>card மேல் வலது switch on ஆகவே இருக்கும்.</td></tr><tr><td>Key fields are saved</td><td>detail view-ல் Endpoint, Bucket, Region, path-style access மற்றும் related fields தெரியும்.</td></tr><tr><td>Upload works</td><td>test image upload செய்து object target bucket-ல் வந்ததா பார்க்கவும்.</td></tr><tr><td>Link opens</td><td>upload-க்கு பிறகு கிடைக்கும் image link திறக்க வேண்டும்.</td></tr><tr><td>Capacity display works</td><td>quota limit enabled என்றால் used capacity மற்றும் configured limit காட்ட வேண்டும்.</td></tr></tbody></table><p>S3 capacity statistics provider bucket-ஐ real time query செய்வதில்லை. ImgBed local file records அடிப்படையில் கணக்கிடுகிறது. S3 configuration save செய்த பிறகு current D1 records-ல் இருந்து quota ledger recalculated ஆகும்.</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="path-style-access-enable-செய்ய-வேண்டுமா" tabindex="-1">path-style access enable செய்ய வேண்டுமா? <a class="header-anchor" href="#path-style-access-enable-செய்ய-வேண்டுமா" aria-label="Permalink to &quot;path-style access enable செய்ய வேண்டுமா?&quot;">​</a></h3><p>பொதுவாக வேண்டாம்.</p><p>உங்கள் provider virtual-hosted-style URLs support செய்யவில்லை என்றால், அல்லது documentation path-style access கேட்கிறது என்றால் மட்டும் enable செய்யவும்.</p><h3 id="cdn-domain-எதற்கு" tabindex="-1">CDN domain எதற்கு? <a class="header-anchor" href="#cdn-domain-எதற்கு" aria-label="Permalink to &quot;CDN domain எதற்கு?&quot;">​</a></h3><p>bucket முன் CDN அல்லது custom access domain வைத்திருந்தால் அதை இங்கு நிரப்பவும்.</p><p>அமைத்த பிறகு generated file links அந்த domain-ஐ முன்னுரிமை தரும். CDN இல்லையெனில் காலியாக விடவும்.</p><h3 id="upload-fail-ஆனால்-என்ன-பார்க்க-வேண்டும்" tabindex="-1">upload fail ஆனால் என்ன பார்க்க வேண்டும்? <a class="header-anchor" href="#upload-fail-ஆனால்-என்ன-பார்க்க-வேண்டும்" aria-label="Permalink to &quot;upload fail ஆனால் என்ன பார்க்க வேண்டும்?&quot;">​</a></h3><ol><li>Endpoint முழு <code>https://</code> URL உடன் உள்ளதா.</li><li>bucket name சரியா.</li><li>Region provider requirement-க்கு பொருந்துகிறதா.</li><li>Access Key ID மற்றும் Secret Access Key முழுமையாக copy செய்யப்பட்டதா.</li><li>key-க்கு target bucket write permission உள்ளதா.</li><li>provider path-style access கேட்கிறதா; கேட்பின் enabled உள்ளதா.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key, Secret Key தயார் செய்யவும்</span></span>
<span class="line"><span>-&gt; Upload Settings திறக்கவும்</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; S3 தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key நிரப்பவும்</span></span>
<span class="line"><span>-&gt; தேவையெனில் CDN domain நிரப்பவும்</span></span>
<span class="line"><span>-&gt; default ஆக path-style access off வைத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; தேவையெனில் quota limit enable செய்யவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; test image upload செய்து பார்க்கவும்</span></span></code></pre></div>`,39)])])}const k=l(c,[["render",r]]);export{f as __pageData,k as default};
